(window.webpackJsonp=window.webpackJsonp||[]).push([[22],{649:function(n,e){n.exports="\x3c!-- \ntitle: MySQL\nsort: \n--\x3e \n\n## 安装\n\n### Debian10\n\n```bash\napt install mariadb-server\n\n# sqlmap问题解决\nsudo apt-get install libmariadb-dev\npip isntall mysqlclient\n```\n\n### Ubuntu+WSL2\n\n```bash\nsudo apt-get install mariadb-server\n```\n\n### Docker\n\n```bash\ndocker pull mariadb\ndocker run -d -p 3306:3306 --name mariadb -e MYSQL_ROOT_PASSWORD=root mariadb\ndocker exec -it <name>/<cid> bash\n```\n\n\n### 更换密码\n\n```bash\n# 开启远程访问\nuse mysql;\nupdate user set host = '%' where user = 'root';\n\nset password = password('1234');\nset password for 'root'@'%' = password('1234');\nflush privileges;  # 立即生效\n```\n\n### 操作\n\n```sql\n# 导入数据库\n> use dbName;\n> source xx.sql;\n\n# 修改表名\n> alter table old_name rename as new_name;\n```\n\n"}}]);